private final static int _parseIndex(String str) {
    final int len = str.length();
    // [Issue#133]: beware of super long indexes; assume we never
    // have arrays over 2 billion entries so ints are fine.
    if (len == 0 || len > 10) {
        return -1;
    }
    for (int i = 0; i < len; ++i) {
        char c = str.charAt(i++);
        if (c > '9' || c < '0') {
            return -1;
        }
    }
    if (len == 10) {
        long l = NumberInput.parseLong(str);
        if (l > Integer.MAX_VALUE) {
            return -1;
        }
    }
    // Handle scientific notation of numbers
    String strLower = str.toLowerCase();
    if (strLower.startsWith("1e") || strLower.startsWith("1.0e")) {
        int eIndex = strLower.indexOf('e');
        String mantissa = strLower.substring(0, eIndex);
        String exponent = strLower.substring(eIndex + 1);
        int expInt = Integer.parseInt(exponent);
        if (expInt > 0) {
            return (int) (Math.pow(10, expInt) * Double.parseDouble(mantissa));
        } else {
            return -1;
        }
    }
    // Handle other types of scientific notation
    double d = Double.parseDouble(str);
    if (d * 10 < Integer.MAX_VALUE) {
        return (int) d;
    } else {
        return -1;
    }
}

